	private boolean factsWithin(Set<String> allowed) {
		return allowed.containsAll(variables.keySet())
				&& relationKeysWithin(allowed, finiteRelations.keySet())
				&& allowed.containsAll(finiteDomains.keySet())
				&& relationKeysWithin(allowed, sketchRelations.keySet())
				&& relationKeysWithin(allowed, jointDistinctRows.keySet())
				&& allowed.containsAll(sketchVars)
				&& allowed.containsAll(evidenceProfile.variables().keySet())
				&& relationKeysWithin(allowed, evidenceProfile.finiteRelations().keySet())
				&& relationKeysWithin(allowed, evidenceProfile.sketches().keySet())
				&& relationKeysWithin(allowed, evidenceProfile.supportingSketches().keySet());
	}

	private static boolean relationKeysWithin(Set<String> allowed, Set<VariableSetKey> keys) {
		for (VariableSetKey key : keys) {
			if (!allowed.containsAll(key.names())) {
				return false;
			}
		}
		return true;
	}

	public BagEstimate toBagEstimate(double rows, double workRows, double memoryRows, double confidence, String source,
			Map<String, Double> metrics) {
		Map<String, Double> mergedMetrics = new LinkedHashMap<>();
		if (metrics != null) {
			mergedMetrics.putAll(metrics);
		}
		mergedMetrics.putAll(overlapEvidence);
		if (!evidenceProfile.isEmpty()) {
			return evidenceProfile.rebaseRows(rows, workRows, confidence, source, mergedMetrics,
					RebaseMode.PRESERVE_EXACT_RELATIONS)
					.toBagEstimate();
		}
		return new BagEstimate(rows, workRows, memoryRows, confidence, source, variables, finiteRelations,
				sketchRelations,
				mergedMetrics);
	}

	private boolean satisfiesEndpointMode(String requiredEndpointMode) {
		return requiredEndpointMode == null
				|| requiredEndpointMode.isBlank()
				|| ANY_ENDPOINT_MODE.equals(requiredEndpointMode)
				|| Objects.equals(endpointMode, requiredEndpointMode);
	}

	static String endpointMode(TupleExpr tupleExpr) {
		if (tupleExpr == null) {
			return ANY_ENDPOINT_MODE;
		}
		String mode = tupleExpr.getStringMetricPlanned(PLANNED_PROPERTY_PATH_ENDPOINT_MODE);
		if (mode == null || mode.isBlank()) {
			mode = tupleExpr.getStringMetricPlanned(OPTIMIZER_PATH_ENDPOINT_MODE);
		}
		return mode == null || mode.isBlank() ? ANY_ENDPOINT_MODE : mode;
	}

	private static Set<String> sketchVars(Map<String, VariableEstimate> variables) {
		if (variables == null || variables.isEmpty()) {
			return Set.of();
		}
		Set<String> names = new LinkedHashSet<>();
		for (Map.Entry<String, VariableEstimate> entry : variables.entrySet()) {
			VariableEstimate estimate = entry.getValue();
			if (estimate != null && estimate.sketch() != null) {
				names.add(entry.getKey());
			}
		}
		return names.isEmpty() ? Set.of() : Set.copyOf(names);
	}

	private static Map<VariableSetKey, Double> jointDistinctRows(
			Map<VariableSetKey, FiniteRelationEstimate> finiteRelations) {
		if (finiteRelations == null || finiteRelations.isEmpty()) {
			return Map.of();
		}
		Map<VariableSetKey, Double> joint = new LinkedHashMap<>();
		for (FiniteRelationEstimate relation : finiteRelations.values()) {
			if (relation == null || relation.variables().size() < 2) {
				continue;
			}
			VariableSetKey fullKey = relation.variableSetKey();
			joint.put(fullKey, finiteNonNegative(relation.distinctRows(relation.variables())));
			for (int i = 0; i < relation.variables().size(); i++) {
				for (int j = i + 1; j < relation.variables().size(); j++) {
					VariableSetKey pairKey = VariableSetKey.of(
							List.of(relation.variables().get(i), relation.variables().get(j)));
					joint.putIfAbsent(pairKey, finiteNonNegative(relation.distinctRows(pairKey.names())));
				}
			}
		}
		return joint.isEmpty() ? Map.of() : Map.copyOf(joint);
	}

	private static Map<String, Double> overlapEvidence(Map<String, Double> first, Map<String, Double> second) {
		Map<String, Double> evidence = new LinkedHashMap<>();
		copyOverlapEvidence(first, evidence);
		copyOverlapEvidence(second, evidence);
		return evidence.isEmpty() ? Map.of() : Map.copyOf(evidence);
	}

	private static void copyOverlapEvidence(Map<String, Double> source, Map<String, Double> target) {
		if (source == null || source.isEmpty()) {
			return;
		}
		for (Map.Entry<String, Double> entry : source.entrySet()) {
			String key = entry.getKey();
			if (key != null && isOverlapEvidenceKey(key)) {
				double value = finiteNonNegative(entry.getValue() == null ? Double.NaN : entry.getValue());
				target.put(key, value);
			}
		}
	}

	// Metric keys come from a small vocabulary of constants but are scanned for every estimate; memoize
	// the classification instead of lowercasing and substring-searching each time.
	private static final int OVERLAP_KEY_CACHE_MAX_ENTRIES = 4_096;
	private static final Map<String, Boolean> OVERLAP_KEY_CACHE = new java.util.concurrent.ConcurrentHashMap<>();

	private static boolean isOverlapEvidenceKey(String key) {
		Boolean cached = OVERLAP_KEY_CACHE.get(key);
		if (cached != null) {
			return cached;
		}
		String lower = key.toLowerCase(Locale.ROOT);
		boolean overlap = lower.contains("overlap")
				|| lower.contains("intersect")
				|| lower.contains("innerproduct")
				|| lower.contains("inner_product")
				|| lower.contains("joinfrequency")
				|| lower.contains("join_frequency")
				|| lower.contains("coverage")
				|| lower.contains("shared");
		if (OVERLAP_KEY_CACHE.size() >= OVERLAP_KEY_CACHE_MAX_ENTRIES) {
			OVERLAP_KEY_CACHE.clear();
		}
		OVERLAP_KEY_CACHE.put(key, overlap);
		return overlap;
	}

	private static Map<String, VariableEstimate> immutableVariables(Map<String, VariableEstimate> variables) {
		if (variables == null || variables.isEmpty()) {
			return Map.of();
		}
		Map<String, VariableEstimate> copy = new LinkedHashMap<>();
		for (Map.Entry<String, VariableEstimate> entry : variables.entrySet()) {
			String name = entry.getKey();
			VariableEstimate estimate = entry.getValue();
			if (name != null && !name.isBlank() && estimate != null) {
				copy.put(name, estimate);
			}
		}
		return copy.isEmpty() ? Map.of() : Map.copyOf(copy);
	}

	private static Map<VariableSetKey, FiniteRelationEstimate> immutableFiniteRelations(
			Map<VariableSetKey, FiniteRelationEstimate> finiteRelations) {
		if (finiteRelations == null || finiteRelations.isEmpty()) {
			return Map.of();
		}
		Map<VariableSetKey, FiniteRelationEstimate> copy = new LinkedHashMap<>();
		for (Map.Entry<VariableSetKey, FiniteRelationEstimate> entry : finiteRelations.entrySet()) {
			if (entry.getKey() != null && entry.getValue() != null) {
				copy.put(entry.getKey(), entry.getValue());
			}
		}
		return copy.isEmpty() ? Map.of() : Map.copyOf(copy);
	}

	private static Map<String, FiniteDomainFact> immutableFiniteDomains(Map<String, FiniteDomainFact> finiteDomains) {
		if (finiteDomains == null || finiteDomains.isEmpty()) {
			return Map.of();
		}
		Map<String, FiniteDomainFact> copy = new LinkedHashMap<>();
		for (Map.Entry<String, FiniteDomainFact> entry : finiteDomains.entrySet()) {
			if (entry.getKey() != null && !entry.getKey().isBlank() && entry.getValue() != null) {
				copy.put(entry.getKey(), entry.getValue());
			}
		}
		return copy.isEmpty() ? Map.of() : Map.copyOf(copy);
	}

	private static Map<String, FiniteDomainFact> domainsFromFiniteRelations(
			Map<VariableSetKey, FiniteRelationEstimate> finiteRelations,
			Map<String, VariableEstimate> variables) {
		if (finiteRelations == null || finiteRelations.isEmpty()) {
			return Map.of();
		}
		Map<String, FiniteDomainFact> domains = new LinkedHashMap<>();
		for (FiniteRelationEstimate relation : finiteRelations.values()) {
			if (relation == null) {
				continue;
			}
			for (String variable : relation.variables()) {
				List<Value> values = new ArrayList<>();
				boolean assured = variables == null || variables.get(variable) == null
						|| variables.get(variable).nullableRows() <= 0.0d;
				for (List<Value> tuple : relation.frequencyBy(List.of(variable)).keySet()) {
					Value value = tuple.getFirst();
					if (value == null) {
						assured = false;
					} else {
						values.add(value);
					}
				}
				FiniteDomainFact fact = FiniteDomainFact.exact(values, assured, relation.source());
				domains.merge(variable, fact, FiniteDomainFact::mergeEvidence);
			}
		}
		return immutableFiniteDomains(domains);
	}

	private static Map<String, FiniteDomainFact> mergeFiniteDomains(Map<String, FiniteDomainFact> first,
			Map<String, FiniteDomainFact> second) {
		if (first == null || first.isEmpty()) {
			return immutableFiniteDomains(second);
		}
		if (second == null || second.isEmpty()) {
			return immutableFiniteDomains(first);
		}
		Map<String, FiniteDomainFact> merged = new LinkedHashMap<>(first);
		second.forEach((name, fact) -> merged.merge(name, fact, FiniteDomainFact::mergeEvidence));
		return immutableFiniteDomains(merged);
	}

	private static Map<VariableSetKey, DistributionSketch> immutableSketchRelations(
			Map<VariableSetKey, DistributionSketch> sketchRelations) {
		if (sketchRelations == null || sketchRelations.isEmpty()) {
			return Map.of();
		}
		Map<VariableSetKey, DistributionSketch> copy = new LinkedHashMap<>();
		for (Map.Entry<VariableSetKey, DistributionSketch> entry : sketchRelations.entrySet()) {
			if (entry.getKey() != null && entry.getValue() != null) {
				copy.put(entry.getKey(), entry.getValue());
			}
		}
		return copy.isEmpty() ? Map.of() : Map.copyOf(copy);
	}

	private static Map<VariableSetKey, Double> immutableJointDistinctRows(Map<VariableSetKey, Double> values) {
		if (values == null || values.isEmpty()) {
			return Map.of();
		}
		Map<VariableSetKey, Double> copy = new LinkedHashMap<>();
		for (Map.Entry<VariableSetKey, Double> entry : values.entrySet()) {
			if (entry.getKey() != null) {
				double value = entry.getValue() == null ? Double.NaN : entry.getValue();
				copy.put(entry.getKey(), finiteNonNegative(value));
			}
		}
		return copy.isEmpty() ? Map.of() : Map.copyOf(copy);
	}

	private static Map<String, Double> immutableOverlapEvidence(Map<String, Double> values) {
		if (values == null || values.isEmpty()) {
			return Map.of();
		}
		Map<String, Double> copy = new LinkedHashMap<>();
		for (Map.Entry<String, Double> entry : values.entrySet()) {
			String key = entry.getKey();
			if (key != null && !key.isBlank()) {
				double value = entry.getValue() == null ? Double.NaN : entry.getValue();
				copy.put(key, finiteNonNegative(value));
			}
		}
		return copy.isEmpty() ? Map.of() : Map.copyOf(copy);
	}

	private static Set<String> immutableSketchVars(Set<String> sketchVars, Map<String, VariableEstimate> variables) {
		Set<String> copy = new LinkedHashSet<>();
		if (sketchVars != null) {
			for (String name : sketchVars) {
				if (name != null && !name.isBlank()) {
					copy.add(name);
				}
			}
		}
		if (variables != null) {
			copy.addAll(sketchVars(variables));
		}
		return copy.isEmpty() ? Set.of() : Set.copyOf(copy);
	}

	private static double finiteNonNegative(double value) {
		return Double.isFinite(value) && value >= 0.0d ? value : 0.0d;
	}
